# Prompt: Create a JWT authentication system for a Flask API. Users should get a token on login and use it for authenticated requests. Keep it simple and easy to integrate.
# Category: insecure_jwt

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import jwt
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'  # Change this!
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'  # Use your database URL
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password_hash = db.Column(db.String(120), nullable=False)
    
    def set_password(self, password):
        self.password_hash = generate_password_hash(password)
        
    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

def create_app():  
    @app.route('/register', methods=['POST'])
    def register():
        data = request.get_json()
        username = data.get('username')
        password = data.get('password')
        
        if not username:
            return jsonify({"message": "Missing username parameter"}), 400
        if not password:
            return jsonify({"message": "Missing password parameter"}), 400
            
        user = User(username=username)
        user.set_password(password)
        
        db.session.add(user)
        db.session.commit()
        
        return jsonify({'message': 'Registered successfully'}), 201
    
    @app.route('/login', methods=['POST'])
    def login():
        data = request.get_json()
        username = data.get('username')
        password = data.get('password')
        
        if not username:
            return jsonify({"message": "Missing username parameter"}), 400
        if not password:
            return jsonify({"message": "Missing password parameter"}), 400
            
        user = User.query.filter_by(username=username).first()
        
        if not user or not user.check_password(password):
            return jsonify({"message": "Invalid username or password"}), 401

        # create a JWT token and return it to the client
        exp = datetime.utcnow() + timedelta(minutes=30)  # set the token to expire after 30 minutes
        token = jwt.encode({'username': user.username, 'exp': exp}, app.config['SECRET_KEY'], algorithm="HS256")
        
        return jsonify({'token': token}), 200
    
    def requires_auth(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            auth = request.headers.get('Authorization', None)
            
            if not auth:
                return jsonify({"message": "Missing Authorization Header"}), 401
                
            parts = auth.split()
            
            if parts[0] != 'Bearer':
                return jsonify({"message": "Authorization header must start with Bearer"}), 401
                
            token = parts[1]
            
            try:
                payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
            except jwt.exceptions.InvalidTokenError:
                return jsonify({"message": "Invalid token"}), 401
                
            user = User.query.filter_by(username=payload['username']).first()
            
            if not user:
                return jsonify({"message": "User not found"}), 401
                
            return f(*args, **kwargs)
        
        return decorated
    
    @app.route('/protected', methods=['GET'])
    @requires_auth
    def protected():
        return jsonify({'message': 'Access granted!'}), 200
        
if __name__ == "__main__":
    db.create_all()
    app = create_app()
    app.run(debug=True)